            var NEW_HEARING_VENUE_TMP_PATH_Q150 = "/ds/var/page/Tmp/AltCourt";
			var MAINTAIN_HEARING = "/ds/MaintainHearing/Hearings";  
					
			function SelectHearing_Popup(){}
				
			SelectHearing_Popup.nextFocusedAdaptorId = function() {  
				var adaptor = FormController.getInstance().getAdaptorById('HearingAdLine1');
				if( null != adaptor ){ return 'HearingAdLine1'; }
				else /**CJR030**/ {	return 'HearingDate2'; } }
            SelectHearing_Popup.lower = {
	            eventBinding: {
		            singleClicks: [ {element: "SelectHearing_CancelBtn"} ],
		            keys: [ { key: Key.F4, element: "SelectHearing_Popup" } ]
	            }
            };  

			function HearingVenueCode(){}
			HearingVenueCode.dataBinding = "/ds/EnterVariableData/Service/hearingVenueCode";	
			HearingVenueCode.helpText = "Unique three digit court location code - list available";
			HearingVenueCode.maxLength = 3;
			HearingVenueCode.isReadOnly = function(){ return true; }
			HearingVenueCode.tabIndex = __tabIdx++;
			
			function HearingVenueLOVBtn() {}
			HearingVenueLOVBtn.tabIndex = __tabIdx++;	
			
			/**  PostBuildX 15a: Can only bind once all elements declared, that's why this code his here, and not above **/
			SelectHearing_Popup.raise = {
				eventBinding: {
					singleClicks: [ {element: "HearingVenueLOVBtn"} ] }	};	
			
			function SelectHearing_OKBtn(){}
			SelectHearing_OKBtn.actionBinding = function()
			{	var hearingId = Services.getValue(SelectHearingGrid.dataBinding);
			 	var code = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/VenueCode");
			 	var name = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/VenueName");
			 	var date = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Date");
			 	var time = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Time");
			 	var ln1  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/Line[1]");
			 	var ln2  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/Line[2]");
			 	var ln3  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/Line[3]");
			 	var ln4  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/Line[4]");
			 	var ln5  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/Line[5]");
			 	var pcd  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/PostCode");
			 	
			 	Services.setValue(HearingVenueCode.dataBinding, code);
			 	Services.setValue(HearingVenueName.dataBinding, name);
			 	Services.setValue(HearingDate2.dataBinding, date);
			 	Services.setValue(HearingTime2.dataBinding, time);
              	Services.setValue(HearingAdLine1.dataBinding, ln1);
    		 	Services.setValue(HearingAdLine2.dataBinding, ln2);
    		 	Services.setValue(HearingAdLine3.dataBinding, ln3);
    		 	Services.setValue(HearingAdLine4.dataBinding, ln4);
    		 	Services.setValue(HearingAdLine5.dataBinding, ln5);
               	Services.setValue(PostCode360.dataBinding, pcd);			 				
             
				FormController.getInstance().hideFormExtensionPopup("SelectHearing");
			}
			SelectHearing_OKBtn.tabIndex = __tabIdx++;
		    SelectHearing_OKBtn.additionalBindings = {
			    eventBinding: {
				    doubleClicks: [ {element: "SelectHearingGrid"} ]
			    }
		    };
			
			function SelectHearing_CancelBtn(){}
			SelectHearing_CancelBtn.tabIndex = __tabIdx++;
			
			function SelectHearingGrid(){}
			SelectHearingGrid.dataBinding = "/ds/EnterVariableData/Service/selectHearingGrid";
			SelectHearingGrid.helpText = "Select the hearing venue";
			SelectHearingGrid.srcData	= "/ds/MaintainHearing/Hearings"; 
			SelectHearingGrid.keyXPath  = "HearingID";
			SelectHearingGrid.rowXPath	= "Hearing";  
			SelectHearingGrid.columns = [
				{xpath: "VenueCode"},
				{xpath: "VenueName"},
				{xpath: "TypeOfHearing"},
				{xpath: "Date", sort: CaseManUtils.sortGridDatesDsc, defaultSort:"true", defaultSortOrder:"descending", transformToDisplay: CaseManUtils.formatGridDate},
				{xpath: "Time",  transformToDisplay: CaseManUtils.convertSecondsToTime}, 
				{xpath: "HearingOutcomeCode"}
			];			
			
			function SelectAltHearingVenue_Popup(){}
			
			SelectAltHearingVenue_Popup.firstFocusedAdaptorId  = function(){
				Services.setFocus("AltHearing_VenueCode"); /**force framework to move to first available field**/}
			
			SelectAltHearingVenue_Popup.nextFocusedAdaptorId = function() {
				return 'AltHearing_VenueLOVBtn'; /**force framework to move to next available field**/}
			
			SelectAltHearingVenue_Popup.lower = {
				eventBinding: {
					singleClicks: [ {element: "AltHearing_CancelBtn"} ],
					keys: [ { key: Key.F4, element: "SelectAltHearingVenue_Popup" } ]
				}
			};
			
			function AltCourtCode(){}
			AltCourtCode.dataBinding = "/ds/EnterVariableData/FastTrack/AltCourtCode";
			AltCourtCode.isReadOnly = function(){ return true; }
			//AltCourtCode.tabIndex = __tabIdx++;
			AltCourtCode.maxLength = 3;
			AltCourtCode.helpText = "Unique LCD three digit court location code – list available";
			AltCourtCode.mandatoryOn = [HearingVenueName.dataBinding];
			AltCourtCode.isMandatory = function() {return HearingVenueName.isMandatory();}
			AltCourtCode.logicOn = [AltCourtCode.dataBinding];
			AltCourtCode.logic = function(xpath) {        		
				var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + AltCourtCode.dataBinding + "]/Name";	 
				var venueName = Services.getValue(xpathName); 	 				
				Services.setValue(HearingVenueName.dataBinding, venueName); }			
			AltCourtCode.enableOn = [HearingVenueName.dataBinding];
			AltCourtCode.isEnabled = function() {
				var isEbld = HearingVenueName.isEnabled();		
				return isEbld; }
				
			function AltHearingVenueLOVBtn() {}
			AltHearingVenueLOVBtn.actionBinding = function() {
				Services.dispatchEvent("SelectAltHearingVenue_Popup", PopupGUIAdaptor.EVENT_RAISE); 
				var venueCode = Services.getValue(HearingVenueCode.dataBinding);
				Services.setValue(AltHearing_VenueCode.dataBinding, venueCode); }
			AltHearingVenueLOVBtn.tabIndex = __tabIdx++;
			AltHearingVenueLOVBtn.enableOn = [HearingVenueName.dataBinding];
			AltHearingVenueLOVBtn.isEnabled = function() {
				return true; }
			AltHearingVenueLOVBtn.additionalBindings = {
				eventBinding: {
					keys: [ { key: Key.F6, element: "HearingVenueCode" }, { key: Key.F6, element: "HearingVenueName" } ]
				}
			};
				
			
			function AltHearing_VenueCode(){}
			AltHearing_VenueCode.tabIndex = __tabIdx++;
			AltHearing_VenueCode.dataBinding = "/ds/EnterVariableData/FastTrack/AltHearing_VenueCode";
			AltHearing_VenueCode.helpText = "Unique three digit court location code - list available.";
			AltHearing_VenueCode.maxLength = 3;
			AltHearing_VenueCode.logicOn = [AltHearing_VenueCode.dataBinding];
			AltHearing_VenueCode.logic = function(xpath) {	
				var code = Services.getValue(AltHearing_VenueCode.dataBinding);			
				if(code != null && code != ""){
					Services.setValue(AltHearing_VenueName.dataBinding, code);		
					Services.setValue(AltCourtCourtsLOVGrid.dataBinding, code);	
					Services.setValue(AltHearing_VenueCode.dataBinding, code);	}
				else{
					Services.setValue(AltHearing_VenueName.dataBinding, "");
					Services.setValue(AltHearing_VenueCode.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Line1.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Line2.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Line3.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Line4.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Line5.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Postcode.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_DXNumber.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_TelephoneNumber.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_FaxNumber.dataBinding, "");
					Services.setValue(AltCourtCourtsLOVGrid.dataBinding, ""); } }

			function AltHearing_VenueName(){}
			AltHearing_VenueName.dataBinding = "/ds/EnterVariableData/FastTrack/AltHearing_VenueName";
			AltHearing_VenueName.tabIndex = __tabIdx++; 
			AltHearing_VenueName.isReadOnly = function(){ return false; }
			AltHearing_VenueName.isTemporary = function(){ return true; }
			AltHearing_VenueName.maxLength = 30;
			AltHearing_VenueName.helpText = "Name of the Court.";
			AltHearing_VenueName.isMandatory = function(){ return true; }
			AltHearing_VenueName.validate = function(){ return null; }
			AltHearing_VenueName.srcData = REF_DATA_XPATH + "/Courts";
			AltHearing_VenueName.rowXPath = "Court";
			AltHearing_VenueName.keyXPath = "Code";
			AltHearing_VenueName.displayXPath = "Name";
			AltHearing_VenueName.logicOn  = [AltHearing_VenueName.dataBinding];
			AltHearing_VenueName.logic = function(xpath) {
				var codeOrName = Services.getValue(AltHearing_VenueName.dataBinding);      	
				var codeXPath = REF_DATA_XPATH + "/Courts/Court[Code = " + AltHearing_VenueName.dataBinding + "]/Code";
				var code = Services.getValue(codeXPath);
				if(code == null) {
					name = Services.getValue(AltHearing_VenueName.dataBinding);     
					code = Services.getValue(REF_DATA_XPATH + "/Courts/Court[Name = " + AltHearing_VenueName.dataBinding + "]/Code"); }
				if( code != null && code != "") { 	
					Services.setValue(AltHearing_VenueCode.dataBinding, code);  }
				else { 
					Services.setValue(AltHearing_VenueName.dataBinding, "");
					Services.setValue(AltHearing_VenueCode.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Line1.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Line2.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Line3.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Line4.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Line5.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_Postcode.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_DXNumber.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_TelephoneNumber.dataBinding, "");
					Services.setValue(AltHearing_ContactDetails_Address_FaxNumber.dataBinding, "");
					Services.setValue(AltCourtCourtsLOVGrid.dataBinding, ""); } }

