			function AltCourtCourtsLOVGrid() {};
			AltCourtCourtsLOVGrid.dataBinding = "/ds/var/page/SelectedLOVRow/AltOwningCourt"; // Changed by Anoop
			AltCourtCourtsLOVGrid.srcData = REF_DATA_XPATH + "/Courts";
			AltCourtCourtsLOVGrid.rowXPath = "Court";
			AltCourtCourtsLOVGrid.keyXPath = "Code";
			AltCourtCourtsLOVGrid.columns = [ {xpath: "Code"}, {xpath: "Name"} ];
			AltCourtCourtsLOVGrid.raise = {
				eventBinding: {
					singleClicks: [ {element: "AltHearing_VenueLOVBtn"} ],
					keys: [ { key: Key.F6, element: "AltHearing_VenueCode" }, { key: Key.F6, element: "AltHearing_VenueName" } ] } };

			AltCourtCourtsLOVGrid.logicOn = [AltCourtCourtsLOVGrid.dataBinding];
			AltCourtCourtsLOVGrid.logic = function(xpath) {
				var id = Services.getValue(AltCourtCourtsLOVGrid.dataBinding);
				if (id != null && id != "") {
					var xpathCode = REF_DATA_XPATH + "/Courts/Court[Id = " + id + "]/Code";		
					var xpathName = REF_DATA_XPATH + "/Courts/Court[Code = " + id + "]/Name";		
					var courtCode = Services.getValue(xpathCode);
					var courtName = Services.getValue(xpathName);
					Services.setValue(AltHearing_VenueCode.dataBinding, id);
					Services.setValue(AltHearing_VenueName.dataBinding, id); }
				else {
					Services.setValue(AltHearing_VenueCode.dataBinding, "");
					Services.setValue(AltHearing_VenueName.dataBinding, ""); } } 
					
			function AltHearing_Address_Grid(){};
			AltHearing_Address_Grid.dataBinding = "/ds/var/page/SelectedGridRow/SelectedAddress"; 
			AltHearing_Address_Grid.srcData = REF_DATA_XPATH + "/Courts/Court[./Code = " + AltHearing_VenueCode.dataBinding + "]/ContactDetails"; 
			AltHearing_Address_Grid.rowXPath = "Address";		// Individual Court/venue
			AltHearing_Address_Grid.keyXPath = "AddressId";  	// Unique identifier for a Court/venue
			AltHearing_Address_Grid.columns = [   				// column bindings
				{xpath: "Line[1]", sort: function(a,b){if(a < b){return 1;};if(a > b){return -1;};return 0;}},
				{xpath: "Line[2]", sort: function(a,b){if(a < b){return 1;};if(a > b){return -1;};return 0;}} ];			
			AltHearing_Address_Grid.retrieveOn = [AltCourtCourtsLOVGrid.dataBinding, AltHearing_VenueCode.dataBinding, AltHearing_VenueName.dataBinding];
			AltHearing_Address_Grid.srcDataOn = [AltCourtCourtsLOVGrid.dataBinding, AltHearing_VenueCode.dataBinding, AltHearing_VenueName.dataBinding];
			
			AltHearing_Address_Grid.logicOn = [AltHearing_Address_Grid.dataBinding, AltCourtCourtsLOVGrid.dataBinding, AltHearing_VenueCode.dataBinding, AltHearing_VenueName.dataBinding];
			AltHearing_Address_Grid.logic = function(xpath) {
				var courtId = Services.getValue(AltCourtCourtsLOVGrid.dataBinding);
				var addressId = Services.getValue(AltHearing_Address_Grid.dataBinding);
				if (courtId != null && courtId != "" && addressId != "" && addressId != null) {	
					var b11 = REF_DATA_XPATH + "/Courts/Court[./Code = ";
					var b13 = "]/ContactDetails/";
					var b12 = b13 + "Address[./AddressId = ";
					var xpathAdd1 = b11+courtId+b12+addressId+"]/Line[1]";	
					var xpathAdd2 = b11+courtId+b12+addressId+"]/Line[2]";	
					var xpathAdd3 = b11+courtId+b12+addressId+"]/Line[3]";	
					var xpathAdd4 = b11+courtId+b12+addressId+"]/Line[4]";	
					var xpathAdd5 = b11+courtId+b12+addressId+"]/Line[5]";	
					var xpathPostcode = b11+courtId+b12+addressId+"]/PostCode";	
					var xpathDXNo  = b11+courtId+b13+"DX";	
					var xpathTelNo = b11+courtId+b13+"TelephoneNumber";	
					var xpathFaxNo = b11+courtId+b13+"FaxNumber";	
					var add1 = Services.getValue(xpathAdd1);
					var add2 = Services.getValue(xpathAdd2);
					var add3 = Services.getValue(xpathAdd3); if(add3 == null)add3 = "";	
					var add4 = Services.getValue(xpathAdd4); if(add4 == null)add4 = "";
					var add5 = Services.getValue(xpathAdd5); if(add5 == null)add5 = "";
					var postcode = Services.getValue(xpathPostcode);		
					var dxNo = Services.getValue(xpathDXNo); if(dxNo == null)dxNo = "";
					var telNo = Services.getValue(xpathTelNo); if(telNo == null)telNo = "";
					var faxNo = Services.getValue(xpathFaxNo); if(faxNo == null)faxNo= "";
					Services.setValue(AltHearing_ContactDetails_Address_Line1.dataBinding, add1);
					Services.setValue(AltHearing_ContactDetails_Address_Line2.dataBinding, add2);
					Services.setValue(AltHearing_ContactDetails_Address_Line3.dataBinding, add3);
					Services.setValue(AltHearing_ContactDetails_Address_Line4.dataBinding, add4);
					Services.setValue(AltHearing_ContactDetails_Address_Line5.dataBinding, add5);
					Services.setValue(AltHearing_ContactDetails_Address_Postcode.dataBinding, postcode);		
					Services.setValue(AltHearing_ContactDetails_Address_DXNumber.dataBinding, dxNo);
					Services.setValue(AltHearing_ContactDetails_Address_TelephoneNumber.dataBinding, telNo);
					Services.setValue(AltHearing_ContactDetails_Address_FaxNumber.dataBinding, faxNo); } } 
			
			function AltHearing_VenueLOVBtn() {}
			AltHearing_VenueLOVBtn.tabIndex = __tabIdx++;			

			function setCaseOwningCourtDetails() {	   	
				var hcrtcode  =  WPU.getCaseOwningCourt();			   
				var addxpath = REF_DATA_XPATH + "/Courts/Court[./Code='"+hcrtcode+"']/ContactDetails/Address"; 
				var contdet = REF_DATA_XPATH + "/Courts/Court[./Code='"+hcrtcode+"']/ContactDetails"; 
				var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code='"+hcrtcode+"']/Name";			
				Services.setValue(AltHearing_VenueCode.dataBinding, hcrtcode);			   	
				Services.setValue(HearingVenueCode.dataBinding, hcrtcode);
				Services.setValue( HearingVenueName.dataBinding, Services.getValue(xpathName));			
				var addAr = Services.getNodes( addxpath );
				if (null != addAr && addAr.length == 1) {	
					var addNode = addAr[0];
					var ln1 = Services.getValue( addxpath+"/Line[1]" );
					var ln2 = Services.getValue( addxpath+"/Line[2]" );
					var ln3 = Services.getValue( addxpath+"/Line[3]" );
					var ln4 = Services.getValue( addxpath+"/Line[4]" );
					var ln5 = Services.getValue( addxpath+"/Line[5]" );
					var pcode = Services.getValue( addxpath+"/PostCode" );
					var dxNo = Services.getValue(contdet+"/DX");
